oxy_webhelp_navlinks = {"rubrik_cc_es_on_saas-d30753e4380":{"topics":[{"title":"Rubrik Cloud Cluster ES for Azure","shortdesc":"<p class=\"shortdesc\">You can use Rubrik Cloud Cluster Elastic Storage for Azure to protect applications         and data within a Microsoft Azure virtual network.<\/p>","href":"saas\/azure_cc_es_rsc.html","attributes":{"data-id":"azure_cc_es_rsc"},"menu":{"hasChildren":false},"tocID":"azure_cc_es_rsc-d30753e4394","next":"azure_cc_es_rsc-d30753e4394"},{"title":"Rubrik Cloud Cluster ES for AWS","shortdesc":"<p class=\"shortdesc\">A Rubrik Cloud Cluster Elastic Storage protects applications and data by running         Rubrik CDM software on Amazon EC2 instances within a virtual private cloud.<\/p>","href":"saas\/aws_cc_es_rsc.html","attributes":{"data-id":"aws_cc_es_rsc"},"menu":{"hasChildren":false},"tocID":"aws_cc_es_rsc-d30753e4556","next":"aws_cc_es_rsc-d30753e4556"},{"title":"Rubrik Cloud Cluster ES for OCI","shortdesc":"<p class=\"shortdesc\">Rubrik Cloud Cluster protects applications and data by running Rubrik CDM software on         Oracle Cloud Infrastructure instances within a virtual private cloud.<\/p>","href":"saas\/oci_cloud_cluster_rsc.html","attributes":{"data-id":"oci_cloud_cluster_rsc"},"menu":{"hasChildren":false},"tocID":"oci_cloud_cluster_rsc-d30753e4670","next":"oci_cloud_cluster_rsc-d30753e4670"},{"title":"Rubrik Cloud Cluster ES for GCP","shortdesc":"<p class=\"shortdesc\">A Rubrik Cloud Cluster protects applications and data by running Rubrik CDM software         on Google Cloud Platform instances within a virtual private cloud.<\/p>","href":"saas\/gcp_cloud_cluster_es_rsc.html","attributes":{"data-id":"gcp_cloud_cluster_es_rsc"},"menu":{"hasChildren":false},"tocID":"gcp_cloud_cluster_es_rsc-d30753e4833","next":"gcp_cloud_cluster_es_rsc-d30753e4833"},{"title":"Rubrik Cloud Cluster recoverability","shortdesc":"<p class=\"shortdesc\">Rebuild your Rubrik Cloud Cluster Elastic Storage instance to recover cluster data         when all other methods for recovering the cluster nodes fail.<\/p>","href":"saas\/cces_recoverability.html","attributes":{"data-id":"cces_recoverability"},"menu":{"hasChildren":false},"tocID":"cces_recoverability-d30753e4926","next":"cces_recoverability-d30753e4926"},{"title":"Adding a node to Cloud Cluster ES","shortdesc":"<p class=\"shortdesc\">Add a node to a Rubrik Cloud Cluster ES deployment to increase capacity and improve         performance.<\/p>","href":"saas\/adding_node_cces.html","attributes":{"data-id":"adding_a_node_to_cc_es"},"menu":{"hasChildren":false},"tocID":"adding_a_node_to_cc_es-d30753e4970","topics":[]},{"title":"Adding a pre-deployed node to Cloud Cluster ES","shortdesc":"<p class=\"shortdesc\">Add a node that you have manually deployed to a Rubrik Cloud Cluster ES deployment in             <span class=\"ph\">RSC<\/span> to increase capacity and improve performance.<\/p>","href":"saas\/adding_node_predeployed_cces.html","attributes":{"data-id":"adding_node_predeployed_cces"},"menu":{"hasChildren":false},"tocID":"adding_node_predeployed_cces-d30753e4981","topics":[]},{"title":"Node removal in <span class=\"ph\">RSC<\/span>","shortdesc":"<p class=\"shortdesc\">If you no longer require a node in a Rubrik cluster, a supported third-party hardware         cluster, or a Rubrik Cloud Cluster, you can remove the node by using <span class=\"ph\">RSC<\/span>.         To remove a node, you must meet the requirements for node removal.<\/p>","href":"saas\/node_removal_rsc_2.html","attributes":{"data-id":"node_removal_rsc"},"menu":{"hasChildren":false},"tocID":"node_removal_rsc-d30753e4995","next":"node_removal_rsc-d30753e4995"},{"title":"Extra dense node migration for CCES clusters","shortdesc":"<p class=\"shortdesc\">Extra dense nodes offer greater storage and performance, without a loss of storage         capacity. Using extra dense nodes, organizations can reduce node counts by half during         migration. Customization options are available through the GraphQL API.<\/p>","href":"saas\/extra_dense_migration_cces_clusters.html","attributes":{"data-id":"extra_dense_migration_cces_clusters"},"menu":{"hasChildren":false},"tocID":"extra_dense_migration_cces_clusters-d30753e5022","topics":[]},{"title":"Multiple AZ support for Cloud Cluster ES","shortdesc":"<p class=\"shortdesc\">Multiple Availability Zone support distributes cluster nodes across multiple         availability zones within a cloud region to improve infrastructure resiliency.<\/p>","href":"saas\/multiple_az_support_cces.html","attributes":{"data-id":"multiple_az_support_cces"},"menu":{"hasChildren":false},"tocID":"multiple_az_support_cces-d30753e5033","topics":[]},{"title":"Rubrik Cloud Cluster ES dynamic scaling","shortdesc":"<p class=\"shortdesc\">Dynamic scaling for Rubrik Cloud Cluster ES on <span class=\"ph\">RSC<\/span> optimizes compute         costs by automatically adjusting the number of active nodes based on workload         demand.<\/p>","href":"saas\/cces_dynamic_scaling.html","attributes":{"data-id":"cces_dynamic_scaling"},"menu":{"hasChildren":false},"tocID":"cces_dynamic_scaling-d30753e5045","next":"cces_dynamic_scaling-d30753e5045"},{"title":"Immutable storage in Cloud Cluster ES","shortdesc":"<p class=\"shortdesc\">Immutability ensures retention policies are enforced and prevents alteration or         deletion of snapshots for the specified period, safeguarding data integrity.<\/p>","href":"common\/cces_immutable_storage.html","attributes":{"data-id":"cces_immutable_storage"},"menu":{"hasChildren":false},"tocID":"cces_immutable_storage-d30753e5070","topics":[]}]}};